final:
module Binary_counter_16(
   input                reset_clk ,
   input                rst_n,
   input  [15:0]        limit,

   output reg [15:0]    Q  
);
    always@(posedge reset_clk or negedge rst_n)begin
        if(!rst_n) Q <= 16'd0;
        else if(Q < limit) Q <= Q + 16'd1;
    end
endmodule
